package jetbrains.mps.lang.test.junit5;

/*Generated by MPS */

import jetbrains.mps.lang.test.launcher.WorkerCallback;
import jetbrains.mps.tool.common.Script;
import jetbrains.mps.tool.common.TestData;
import jetbrains.mps.tool.environment.Environment;
import jetbrains.mps.baseLanguage.unitTest.platform.TestSessionConfig;
import java.util.List;
import java.io.File;
import jetbrains.mps.baseLanguage.unitTest.platform.SystemProperties;
import jetbrains.mps.lang.test.junit5.tcutil.JUnit5TestExecutionListener;
import java.util.ArrayList;
import org.jetbrains.mps.openapi.model.SNode;
import jetbrains.mps.project.Project;
import jetbrains.mps.classloading.ClassLoaderManager;
import jetbrains.mps.persistence.PersistenceRegistry;
import org.jetbrains.mps.openapi.module.SModule;
import jetbrains.mps.project.facets.TestsFacet;
import jetbrains.mps.smodel.Generator;

public class ScriptJUnit5Launcher extends AbstractJUnit5Launcher {

  public static final String TEST_REPORTS_DIR = "launchtests.testReportsDir";
  public static final String TEST_REPORTS_OPENTEST = "launchtests.testReportsOpenTest";

  private final WorkerCallback myWorkerCallback;
  private final Script myWhatToDo;
  private final TestData myTestPlan;

  public ScriptJUnit5Launcher(Script whatToDo, Environment environment, TestData testData, WorkerCallback callback) {
    super(environment);
    // I need Environment here, not mps.Platform, to pass it down to EnvironmentAware tests. However, could avoid passing it
    // to superclass and initialize TestSession here directly
    this.myWhatToDo = whatToDo;
    myWorkerCallback = callback;
    myTestPlan = testData;
  }

  @Override
  public int launchTests() {
    FailureDetector failureDetector = new FailureDetector();

    launchTestsWithSession(collectTestClasses(), failureDetector);

    if (failureDetector.hasFailures()) {
      failureDetector.flushErrors(myWorkerCallback);
    }
    return failureDetector.failuresCount();
  }

  @Override
  public TestSessionConfig configureSession(TestSessionConfig config) {
    List<File> projectDirectories = myWhatToDo.getProjectDirectories();
    if (!(projectDirectories.isEmpty())) {
      if (projectDirectories.size() > 1) {
        myWorkerCallback.error("only one project directory can be specified", new IllegalStateException());
      }
      config = config.withSystemProperty(SystemProperties.PROJECT_PATH, projectDirectories.get(0).getAbsolutePath());
    }
    return config;
  }

  @Override
  protected JUnit5TestExecutionListener createTestExecutionListener() {
    return new JUnit5TestExecutionListener() {
      @Override
      protected void flushSystemStreams() {
        // NOP: avoid attempting to flush stdout/stderr in order not to deadlock; MPS-37852
      }
    };
  }

  private List<Class<?>> collectTestClasses() {
    final List<Class<?>> testClasses = new ArrayList<>();
    final TestDiscoveryVisitor visitor = new TestDiscoveryVisitor() {
      @Override
      public void visitTestRoot(SNode testRootNode, String testClassName, ClassLoader moduleClassLoader) {
        try {
          testClasses.add(moduleClassLoader.loadClass(testClassName));

        } catch (ClassNotFoundException e) {
          myWorkerCallback.fatal("error building test suite", e);
        }
      }
    };
    // FIXME don't need Project, just a convenience for now, shall access platform.find(LanguageRegistry).withModuleRuntime(modulePtr).loadClass() or findResource(), instead (once supply list of tests)
    // we rely on project MA being delegate for CLM repository's MA
    final Project project = myEnvironment.createEmptyProject();

    project.getModelAccess().runReadAction(() -> {
      TestDiscovery discovery = new TestDiscovery(myEnvironment.getPlatform().findComponent(ClassLoaderManager.class), visitor);
      PersistenceRegistry pf = myEnvironment.getPlatform().findComponent(PersistenceRegistry.class);

      for (TestData.ModuleRecord tm : myTestPlan.testModules) {
        SModule testModule = pf.createModuleReference(tm.modulePtr).resolve(project.getRepository());
        if (testModule == null) {
          myWorkerCallback.fatal("Can't find module %s in a repository", null);
          continue;
        }
        if (testModule.getFacet(TestsFacet.class) == null) {
          if (false == testModule instanceof Generator) {
            myWorkerCallback.info(String.format("Module %s doesn't have 'tests' facet, skipped", testModule.getModuleName()));
          }
        }
        discovery.surveyModule(testModule);
      }
    });

    myEnvironment.closeProject(project);

    return testClasses;
  }

  @Override
  protected File getTestReportsDir() {
    String property = myWhatToDo.getProperty(TEST_REPORTS_DIR);
    if (property == null) {
      return null;
    }
    File dir = new File(property);
    if (!(dir.exists())) {
      if (!(dir.mkdirs())) {
        myWorkerCallback.error("could not create directory for test reports: " + dir.getAbsolutePath());
        return null;
      }
    }
    if (!(dir.isDirectory())) {
      myWorkerCallback.error("not a directory: " + dir.getAbsolutePath());
      return null;
    }
    return dir;
  }

  @Override
  protected boolean isOpenTestReport() {
    String property = myWhatToDo.getProperty(TEST_REPORTS_OPENTEST);
    return (property != null ? Boolean.valueOf(property) : false);
  }

  @Override
  protected boolean isRunningOnTeamCity() {
    return myWhatToDo.getProperty("teamcity.version") != null;
  }

}
